  1→/**
  2→ * Function executor for the Shatter TypeScript frontend.
  3→ *
  4→ * Compiles TypeScript source to JavaScript, executes the target function
  5→ * with provided inputs in a sandboxed context, and returns the result
  6→ * with performance metrics and (for instrumented code) branch decisions.
  7→ */
  8→
  9→import * as ts from "typescript";
 10→import * as fs from "node:fs";
 11→import * as vm from "node:vm";
 12→import * as path from "node:path";
 13→import { createRequire } from "node:module";
 14→import { reconstructValue } from "./reconstruct.js";
 15→import type {
 16→  ExecuteResponse,
 17→  ErrorInfo,
 18→  ErrorCategory,
 19→  PerformanceMetrics,
 20→  BranchDecision,
 21→  SymConstraint,
 22→  SymExpr,
 23→  SideEffect,
 24→  TruncationInfo,
 25→  TraceEvent,
 26→  ScopeEvent,
 27→} from "./protocol.js";
 28→import { RECORD_FUNCTION, BRANCH_FUNCTION, SCOPE_EVENT_FUNCTION, MOCK_REGISTRY, MOCK_CALL_FUNCTION } from "./instrumentor.js";
 29→import type { MockConfig, ExternalCall } from "./protocol.js";
 30→import { REACT_MODULE_NAMES, getReactShim } from "./react-shim.js";
 31→
 32→export const DEFAULT_EXEC_TIMEOUT_MS = 15_000;
 33→
 34→/** Default number of head console lines to keep before truncation. */
 35→export const CAPTURE_HEAD_LINES = 50;
 36→/** Default number of tail console lines to keep after truncation. */
 37→export const CAPTURE_TAIL_LINES = 20;
 38→/** Maximum total bytes for captured console output before truncation. */
 39→export const CAPTURE_MAX_BYTES = 6144;
 40→/** Maximum bytes for a single side-effect message. */
 41→export const MESSAGE_MAX_BYTES = 4096;
 42→
 43→/**
 44→ * Read SHATTER_EXEC_TIMEOUT env var (seconds) and return milliseconds.
 45→ * Default: 15s. Ignores non-positive or non-numeric values.
 46→ */
 47→export function getExecTimeoutMs(): number {
 48→  const raw = process.env["SHATTER_EXEC_TIMEOUT"];
 49→  if (raw !== undefined) {
 50→    const secs = parseFloat(raw);
 51→    if (Number.isFinite(secs) && secs > 0) {
 52→      return secs * 1000;
 53→    }
 54→  }
 55→  return DEFAULT_EXEC_TIMEOUT_MS;
 56→}
 57→
 58→const VALIDATION_ERROR_PATTERNS = /Validation|Invalid|BadRequest|Forbidden|Unauthorized|NotFound/i;
 59→const RUNTIME_ERROR_TYPES = new Set(["TypeError", "ReferenceError", "SyntaxError", "RangeError", "URIError"]);
 60→
 61→/**
 62→ * Classify an error into a structured category using language-level signals.
 63→ * - validation: custom error subclasses or names suggesting deliberate input rejection
 64→ * - runtime: JS built-in error types indicating accidental failures
 65→ * - infrastructure: timeouts and system-level failures
 66→ */
 67→export function classifyError(errorType: string, message: string): ErrorCategory {
 68→  if (/timed?\s*out/i.test(message) || errorType === "ERR_SCRIPT_EXECUTION_TIMEOUT") {
 69→    return "infrastructure";
 70→  }
 71→  if (VALIDATION_ERROR_PATTERNS.test(errorType) || VALIDATION_ERROR_PATTERNS.test(message)) {
 72→    return "validation";
 73→  }
 74→  if (RUNTIME_ERROR_TYPES.has(errorType)) {
 75→    return "runtime";
 76→  }
 77→  return "unknown";
 78→}
 79→
 80→/** Cache of compiled modules to avoid re-transpiling on every execute call. */
 81→const compiledModuleCache = new Map<string, Record<string, unknown>>();
 82→
 83→/**
 84→ * Proxy console used in VM sandboxes. Delegates all calls to `consoleTarget`,
 85→ * which can be swapped at execution time to capture output as side effects.
 86→ */
 87→let consoleTarget: Console = console;
 88→
 89→const consoleProxy = new Proxy(console, {
 90→  get(_target, prop, receiver) {
 91→    const value = Reflect.get(consoleTarget, prop, receiver);
 92→    if (typeof value === "function") {
 93→      return value.bind(consoleTarget);
 94→    }
 95→    return value;
 96→  },
 97→});
 98→
 99→/**
100→ * Set the project root for module resolution. When set, NODE_PATH includes
101→ * the project's node_modules directory so createRequire() resolves packages.
102→ */
103→export function setProjectRoot(projectRoot: string | null | undefined): void {
104→  if (projectRoot) {
105→    const nodeModules = path.join(projectRoot, "node_modules");
106→    const existing = process.env["NODE_PATH"] ?? "";
107→    if (!existing.split(path.delimiter).includes(nodeModules)) {
108→      process.env["NODE_PATH"] = existing ? `${nodeModules}${path.delimiter}${existing}` : nodeModules;
109→      // Force Node to re-read NODE_PATH for future require calls
110→      require("module").Module._initPaths();
111→    }
112→  }
113→}
114→
115→/**
116→ * Wrap a require function to intercept React module imports for .tsx files.
117→ * Non-.tsx files get the original require unchanged.
118→ */
119→function wrapRequireWithReactShim(
120→  originalRequire: NodeRequire,
121→  filePath: string | undefined,
122→): NodeRequire {
123→  if (!filePath || !filePath.endsWith(".tsx")) return originalRequire;
124→
125→  const wrapped = ((modulePath: string) => {
126→    if (REACT_MODULE_NAMES.has(modulePath)) {
127→      return getReactShim(modulePath);
128→    }
129→    return originalRequire(modulePath);
130→  }) as NodeRequire;
131→
132→  // Preserve require.resolve and require.cache for compatibility
133→  wrapped.resolve = originalRequire.resolve;
134→  wrapped.cache = originalRequire.cache;
135→  wrapped.extensions = originalRequire.extensions;
136→  wrapped.main = originalRequire.main;
137→
138→  return wrapped;
139→}
140→
141→/**
142→ * Transpile a TypeScript file to JavaScript and return the exports object.
143→ *
144→ * Results are cached by absolute file path.
145→ */
146→function loadModule(filePath: string): Record<string, unknown> {
147→  const absolutePath = path.resolve(filePath);
148→  const cached = compiledModuleCache.get(absolutePath);
149→  if (cached) return cached;
150→
151→  const source = fs.readFileSync(absolutePath, "utf-8");
152→  const result = ts.transpileModule(source, {
153→    compilerOptions: {
154→      target: ts.ScriptTarget.ES2022,
155→      module: ts.ModuleKind.CommonJS,
156→      esModuleInterop: true,
157→      strict: true,
158→      jsx: ts.JsxEmit.ReactJSX,
159→    },
160→    fileName: absolutePath,
161→  });
162→
163→  const targetRequire = wrapRequireWithReactShim(createRequire(absolutePath), absolutePath);
164→  const moduleExports: Record<string, unknown> = {};
165→  const moduleObj = { exports: moduleExports };
166→
167→  const sandbox = vm.createContext({
168→    module: moduleObj,
169→    exports: moduleExports,
170→    require: targetRequire,
171→    console: consoleProxy,
172→    process,
173→    Buffer,
174→    setTimeout,
175→    clearTimeout,
176→    setInterval,
177→    clearInterval,
178→    __filename: absolutePath,
179→    __dirname: path.dirname(absolutePath),
180→  });
181→
182→  vm.runInContext(result.outputText, sandbox, { filename: absolutePath, timeout: getExecTimeoutMs() });
183→
184→  // After CommonJS execution, module.exports may have been reassigned
185→  const finalExports = (sandbox as Record<string, unknown>)["module"] as { exports: Record<string, unknown> };
186→  const resolvedExports = finalExports.exports;
187→
188→  compiledModuleCache.set(absolutePath, resolvedExports);
189→  return resolvedExports;
190→}
191→
192→/**
193→ * Look up a function from the file path and function name.
194→ *
195→ * The function name may be a simple name like "classifyNumber" which is
196→ * looked up directly on the module exports. If it contains a colon
197→ * (file:function format from the analyze phase), the file portion is
198→ * stripped and only the function name is used.
199→ */
200→function resolveFunction(
201→  filePath: string,
202→  functionRef: string,
203→): (...args: unknown[]) => unknown {
204→  // Strip file prefix if present (e.g. "examples/foo.ts:myFunc" → "myFunc")
205→  const funcName = functionRef.includes(":")
206→    ? functionRef.split(":").pop()!
207→    : functionRef;
208→
209→  const moduleExports = loadModule(filePath);
210→  const fn = moduleExports[funcName];
211→
212→  if (typeof fn !== "function") {
213→    throw new Error(
214→      `Function "${funcName}" not found in exports of ${filePath}. ` +
215→      `Available exports: ${Object.keys(moduleExports).join(", ")}`,
216→    );
217→  }
218→
219→  return fn as (...args: unknown[]) => unknown;
220→}
221→
222→/**
223→ * Run garbage collection if --expose-gc is enabled.
224→ * This gives more accurate heap measurements by clearing unreachable objects.
225→ */
226→function tryGc(): void {
227→  if (typeof globalThis.gc === "function") {
228→    globalThis.gc();
229→  }
230→}
231→
232→/** Result of measuring a function execution. */
233→interface MeasuredExecution {
234→  returnValue: unknown;
235→  thrownError: ErrorInfo | null;
236→  performance: PerformanceMetrics;
237→}
238→
239→/**
240→ * Execute a callback with full performance instrumentation.
241→ *
242→ * Measures wall time via process.hrtime.bigint(), CPU time via process.cpuUsage(),
243→ * and heap delta via process.memoryUsage(). Optionally runs GC before measurement
244→ * if --expose-gc is enabled.
245→ */
246→async function measureExecution(fn: () => unknown): Promise<MeasuredExecution> {
247→  tryGc();
248→
249→  const startMem = process.memoryUsage();
250→  const startCpu = process.cpuUsage();
251→  const startTime = process.hrtime.bigint();
252→
253→  let returnValue: unknown = null;
254→  let thrownError: ErrorInfo | null = null;
255→
256→  try {
257→    const syncResult = fn();
258→    // If the function returned a Promise (async function), await it with timeout
259→    if (syncResult != null && typeof (syncResult as PromiseLike<unknown>).then === 'function') {
260→      const timeoutMs = getExecTimeoutMs();
261→      returnValue = await Promise.race([
262→        syncResult as Promise<unknown>,
263→        new Promise<never>((_, reject) =>
264→          setTimeout(() => reject(new Error("async execution timed out")), timeoutMs)
265→        ),
266→      ]);
267→    } else {
268→      returnValue = syncResult;
269→    }
270→  } catch (e: unknown) {
271→    const err = e as { constructor?: { name?: string }; message?: string; stack?: string };
272→    const errorType = err.constructor?.name ?? "Error";
273→    const errorMessage = String(err.message ?? e);
274→    thrownError = {
275→      error_type: errorType,
276→      message: errorMessage,
277→      stack: err.stack ?? null,
278→      error_category: classifyError(errorType, errorMessage),
279→    };
280→  }
281→
282→  const endTime = process.hrtime.bigint();
283→  const endCpu = process.cpuUsage(startCpu);
284→  const endMem = process.memoryUsage();
285→
286→  const wallTimeNs = endTime - startTime;
287→  const wallTimeMs = Number(wallTimeNs) / 1_000_000;
288→  const cpuTimeUs = endCpu.user + endCpu.system;
289→
290→  return {
291→    returnValue,
292→    thrownError,
293→    performance: {
294→      wall_time_ms: wallTimeMs,
295→      cpu_time_us: cpuTimeUs,
296→      heap_used_bytes: Math.max(0, endMem.heapUsed - startMem.heapUsed),
297→      heap_allocated_bytes: Math.max(0, endMem.heapTotal - startMem.heapTotal),
298→    },
299→  };
300→}
301→
302→/** Execution result before being wrapped in a protocol response. */
303→interface RawExecuteResult {
304→  return_value: unknown;
305→  thrown_error: ErrorInfo | null;
306→  performance: PerformanceMetrics;
307→  branch_path: BranchDecision[];
308→  path_constraints: SymConstraint[];
309→  lines_executed: number[];
310→  side_effects: SideEffect[];
311→  calls_to_external: ExternalCall[];
312→  scope_events: TraceEvent[];
313→}
314→
315→/**
316→ * Truncate a message string to fit within maxBytes.
317→ * If truncated, appends a suffix indicating the message was cut.
318→ */
319→export function truncateMessage(msg: string, maxBytes: number = MESSAGE_MAX_BYTES): string {
320→  const bytes = Buffer.byteLength(msg, "utf-8");
321→  if (bytes <= maxBytes) return msg;
322→  const suffix = "…[truncated]";
323→  const suffixBytes = Buffer.byteLength(suffix, "utf-8");
324→  const target = maxBytes - suffixBytes;
325→  let end = Math.min(msg.length, target);
326→  while (Buffer.byteLength(msg.slice(0, end), "utf-8") > target && end > 0) {
327→    end--;
328→  }
329→  return msg.slice(0, end) + suffix;
330→}
331→
332→/**
333→ * Truncate console_output side effects if they exceed head+tail line limits.
334→ * Returns the (possibly truncated) effects array and truncation metadata.
335→ */
336→export function truncateSideEffects(
337→  effects: SideEffect[],
338→  headLines: number = CAPTURE_HEAD_LINES,
339→  tailLines: number = CAPTURE_TAIL_LINES,
340→): { effects: SideEffect[]; truncation?: TruncationInfo } {
341→  const consoleIndices: number[] = [];
342→  for (let i = 0; i < effects.length; i++) {
343→    const effect = effects[i];
344→    if (effect !== undefined && effect.kind === "console_output") {
345→      consoleIndices.push(i);
346→    }
347→  }
348→
349→  const consoleCount = consoleIndices.length;
350→  if (consoleCount <= headLines + tailLines) {
351→    return { effects };
352→  }
353→
354→  let originalBytes = 0;
355→  for (const idx of consoleIndices) {
356→    const e = effects[idx];
357→    if (e !== undefined && e.kind === "console_output") {
358→      originalBytes += Buffer.byteLength(e.message, "utf-8");
359→    }
360→  }
361→
362→  const keepHead = new Set(consoleIndices.slice(0, headLines));
363→  const keepTail = new Set(consoleIndices.slice(-tailLines));
364→  const truncatedCount = consoleCount - headLines - tailLines;
365→
366→  let keptBytes = 0;
367→  for (const idx of [...keepHead, ...keepTail]) {
368→    const e = effects[idx];
369→    if (e !== undefined && e.kind === "console_output") {
370→      keptBytes += Buffer.byteLength(e.message, "utf-8");
371→    }
372→  }
373→  const truncatedBytes = originalBytes - keptBytes;
374→
375→  const result: SideEffect[] = [];
376→  let markerInserted = false;
377→  for (let i = 0; i < effects.length; i++) {
378→    const effect = effects[i];
379→    if (effect === undefined) continue;
380→    if (effect.kind !== "console_output") {
381→      result.push(effect);
382→    } else if (keepHead.has(i)) {
383→      result.push(effect);
384→    } else if (keepTail.has(i)) {
385→      result.push(effect);
386→    } else if (!markerInserted) {
387→      result.push({
388→        kind: "console_output",
389→        level: "info",
390→        message: `[…truncated ${truncatedCount} lines / ${truncatedBytes} bytes…]`,
391→      });
392→      markerInserted = true;
393→    }
394→  }
395→
396→  return {
397→    effects: result,
398→    truncation: {
399→      was_truncated: true,
400→      original_lines: consoleCount,
401→      original_bytes: originalBytes,
402→    },
403→  };
404→}
405→
406→/**
407→ * Create an intercepting console that records all output as side effects.
408→ *
409→ * Captures: log, warn, error, info, debug (level mapped 1:1),
410→ * dir/table/dirxml (→ "log"), trace (→ "debug"), count/countReset (→ "log"),
411→ * time/timeEnd/timeLog (→ "log"). Non-output methods (group, clear, assert,
412→ * profile, timeStamp) delegate to the real console.
413→ */
414→function createCapturingConsole(sideEffects: SideEffect[]): Console {
415→  const makeLogger = (level: string) => (...args: unknown[]): void => {
416→    const message = truncateMessage(args.map((a) =>
417→      typeof a === "string" ? a : JSON.stringify(a) ?? String(a)
418→    ).join(" "));
419→    sideEffects.push({ kind: "console_output", level, message });
420→  };
421→
422→  const logFn = makeLogger("log");
423→  const debugFn = makeLogger("debug");
424→
425→  // Counters for console.count / console.countReset
426→  const counters = new Map<string, number>();
427→
428→  // Timers for console.time / console.timeEnd / console.timeLog
429→  const timers = new Map<string, number>();
430→
431→  return {
432→    log: logFn,
433→    warn: makeLogger("warn"),
434→    error: makeLogger("error"),
435→    info: makeLogger("info"),
436→    debug: debugFn,
437→    dir: (...args: unknown[]) => logFn(...args),
438→    table: (...args: unknown[]) => logFn(...args),
439→    dirxml: (...args: unknown[]) => logFn(...args),
440→    trace: (...args: unknown[]) => {
441→      debugFn("Trace:", ...args);
442→    },
443→    count: (label = "default") => {
444→      const n = (counters.get(label) ?? 0) + 1;
445→      counters.set(label, n);
446→      logFn(`${label}: ${n}`);
447→    },
448→    countReset: (label = "default") => {
449→      counters.set(label, 0);
450→    },
451→    time: (label = "default") => {
452→      timers.set(label, performance.now());
453→    },
454→    timeEnd: (label = "default") => {
455→      const start = timers.get(label);
456→      if (start !== undefined) {
457→        logFn(`${label}: ${(performance.now() - start).toFixed(3)}ms`);
458→        timers.delete(label);
459→      }
460→    },
461→    timeLog: (label = "default", ...args: unknown[]) => {
462→      const start = timers.get(label);
463→      if (start !== undefined) {
464→        logFn(`${label}: ${(performance.now() - start).toFixed(3)}ms`, ...args);
465→      }
466→    },
467→    assert: console.assert,
468→    clear: console.clear,
469→    group: console.group,
470→    groupCollapsed: console.groupCollapsed,
471→    groupEnd: console.groupEnd,
472→    profile: console.profile,
473→    profileEnd: console.profileEnd,
474→    timeStamp: console.timeStamp,
475→    Console: console.Console,
476→  } as unknown as Console;
477→}
478→
479→/**
480→ * Create a process-like object that intercepts stdout/stderr writes
481→ * and records them as side effects.
482→ */
483→function createCapturingProcess(sideEffects: SideEffect[]): typeof process {
484→  const makeStreamWriter = (level: string) => {
485→    const originalStream = level === "stdout" ? process.stdout : process.stderr;
486→    return new Proxy(originalStream, {
487→      get(target, prop) {
488→        if (prop === "write") {
489→          return (chunk: string | Uint8Array, ...rest: unknown[]): boolean => {
490→            const text = typeof chunk === "string" ? chunk : new TextDecoder().decode(chunk);
491→            const trimmed = text.replace(/\n$/, "");
492→            if (trimmed.length > 0) {
493→              const message = truncateMessage(trimmed);
494→              sideEffects.push({ kind: "console_output", level, message });
495→            }
496→            return true;
497→          };
498→        }
499→        const val = Reflect.get(target, prop, target);
500→        return typeof val === "function" ? val.bind(target) : val;
501→      },
502→    });
503→  };
504→
505→  return new Proxy(process, {
506→    get(target, prop) {
507→      if (prop === "stdout") return makeStreamWriter("stdout");
508→      if (prop === "stderr") return makeStreamWriter("stderr");
509→      const val = Reflect.get(target, prop, target);
510→      return typeof val === "function" ? val.bind(target) : val;
511→    },
512→  });
513→}
514→
515→/**
516→ * Execute a function with the given inputs and capture the result.
517→ */
518→export async function executeFunction(
519→  filePath: string,
520→  functionRef: string,
521→  inputs: unknown[],
522→): Promise<RawExecuteResult> {
523→  const fn = resolveFunction(filePath, functionRef);
524→
525→  const sideEffects: SideEffect[] = [];
526→  const previousTarget = consoleTarget;
527→  consoleTarget = createCapturingConsole(sideEffects);
528→
529→  let metrics: MeasuredExecution;
530→  try {
531→    const reconstructedInputs = inputs.map(reconstructValue);
532→    metrics = await measureExecution(() => fn(...reconstructedInputs));
533→  } finally {
534→    consoleTarget = previousTarget;
535→  }
536→
537→  if (metrics.thrownError) {
538→    sideEffects.push({
539→      kind: "thrown_error",
540→      error_type: metrics.thrownError.error_type,
541→      message: metrics.thrownError.message,
542→      stack: metrics.thrownError.stack,
543→    });
544→  }
545→
546→  return {
547→    return_value: metrics.returnValue ?? null,
548→    thrown_error: metrics.thrownError,
549→    side_effects: sideEffects,
550→    branch_path: [],
551→    path_constraints: [],
552→    lines_executed: [],
553→    performance: metrics.performance,
554→    calls_to_external: [],
555→    scope_events: [],
556→  };
557→}
558→
559→/**
560→ * Execute instrumented TypeScript source code with branch-recording callbacks.
561→ *
562→ * The instrumented source must contain __shatter_record() and __shatter_branch()
563→ * calls inserted by the instrumentor. This function defines those callbacks,
564→ * executes the code, and collects the branch decisions.
565→ */
566→export async function executeInstrumented(
567→  instrumentedSource: string,
568→  functionName: string,
569→  inputs: unknown[],
570→  mocks: MockConfig[] = [],
571→  sourceFilePath?: string,
572→): Promise<RawExecuteResult> {
573→  // Transpile instrumented TS to JS
574→  const jsResult = ts.transpileModule(instrumentedSource, {
575→    compilerOptions: {
576→      target: ts.ScriptTarget.ES2022,
577→      module: ts.ModuleKind.CommonJS,
578→      esModuleInterop: true,
579→      strict: true,
580→      jsx: ts.JsxEmit.ReactJSX,
581→    },
582→    ...(sourceFilePath ? { fileName: sourceFilePath } : {}),
583→  });
584→
585→  const linesExecuted: number[] = [];
586→  const branchDecisions: BranchDecision[] = [];
587→  const sideEffects: SideEffect[] = [];
588→  const externalCalls: ExternalCall[] = [];
589→  const scopeEvents: TraceEvent[] = [];
590→
591→  // Define the runtime callbacks
592→  const recordFn = (line: number): void => {
593→    linesExecuted.push(line);
594→  };
595→
596→  const branchFn = (
597→    branchId: number,
598→    line: number,
599→    conditionResult: boolean,
600→    symExpr: SymExpr,
601→  ): boolean => {
602→    const constraint: SymConstraint = symExpr.kind !== "unknown"
603→      ? { kind: "expr", expr: symExpr }
604→      : { kind: "unknown", hint: "unsupported expression" };
605→
606→    const decision: BranchDecision = {
607→      branch_id: branchId,
608→      line,
609→      taken: conditionResult,
610→      constraint,
611→    };
612→    branchDecisions.push(decision);
613→    scopeEvents.push({ type: "branch", decision });
614→
615→    return conditionResult;
616→  };
617→
618→  const scopeEventFn = (scopeId: number, kind: string): void => {
619→    const event: ScopeEvent = kind.startsWith("loop")
620→      ? { kind: kind as "loop_enter" | "loop_exit", loop_id: scopeId }
621→      : { kind: kind as "call_enter" | "call_exit", call_site_id: scopeId };
622→    scopeEvents.push({ type: "scope", event });
623→  };
624→
625→  // Build mock registry from MockConfig array
626→  const mockRegistry: Record<string, (...args: unknown[]) => unknown> = {};
627→  for (const mock of mocks) {
628→    if (mock.default_behavior === "passthrough") {
629→      continue;
630→    }
631→    let callIndex = 0;
632→    const returnValues = mock.return_values;
633→    mockRegistry[mock.symbol] = (...args: unknown[]): unknown => {
634→      if (returnValues.length > 0) {
635→        const idx = mock.default_behavior === "repeat_last"
636→          ? Math.min(callIndex, returnValues.length - 1)
637→          : callIndex % returnValues.length;
638→        callIndex++;
639→        return returnValues[idx];
640→      }
641→      return undefined;
642→    };
643→  }
644→
645→  // Mock call recorder
646→  const mockCallFn = (
647→    moduleName: string,
648→    symbolName: string,
649→    args: unknown[],
650→    returnValue: unknown,
651→  ): void => {
652→    externalCalls.push({
653→      symbol: `${moduleName}:${symbolName}`,
654→      args: Array.isArray(args) ? args : [],
655→      return_value: returnValue,
656→    });
657→  };
658→
659→  // Build the execution context with capturing console and process
660→  const capturingConsole = createCapturingConsole(sideEffects);
661→  const capturingProc = createCapturingProcess(sideEffects);
662→  const rawRequire = sourceFilePath ? createRequire(path.resolve(sourceFilePath)) : require;
663→  const sandboxRequire = wrapRequireWithReactShim(rawRequire, sourceFilePath);
664→  const moduleExports: Record<string, unknown> = {};
665→  const moduleObj = { exports: moduleExports };
666→
667→  const sandbox = vm.createContext({
668→    module: moduleObj,
669→    exports: moduleExports,
670→    require: sandboxRequire,
671→    console: capturingConsole,
672→    process: capturingProc,
673→    Buffer,
674→    setTimeout,
675→    clearTimeout,
676→    setInterval,
677→    clearInterval,
678→    ...(sourceFilePath ? { __filename: sourceFilePath, __dirname: path.dirname(sourceFilePath) } : {}),
679→    [RECORD_FUNCTION]: recordFn,
680→    [BRANCH_FUNCTION]: branchFn,
681→    [SCOPE_EVENT_FUNCTION]: scopeEventFn,
682→    [MOCK_REGISTRY]: mockRegistry,
683→    [MOCK_CALL_FUNCTION]: mockCallFn,
684→  });
685→
686→  vm.runInContext(jsResult.outputText, sandbox, { filename: sourceFilePath ?? "instrumented.js", timeout: getExecTimeoutMs() });
687→
688→  // Resolve the function from the module exports
689→  const finalExports = (sandbox as Record<string, unknown>)["module"] as { exports: Record<string, unknown> };
690→
691→  // Snapshot module-level variables before execution
692→  const exportKeys = Object.keys(finalExports.exports).filter(
693→    (k) => typeof finalExports.exports[k] !== "function",
694→  );
695→  const beforeSnapshot = new Map<string, unknown>();
696→  for (const key of exportKeys) {
697→    beforeSnapshot.set(key, structuredClone(finalExports.exports[key]));
698→  }
699→
700→  const fn = finalExports.exports[functionName];
701→
702→  if (typeof fn !== "function") {
703→    throw new Error(
704→      `Function "${functionName}" not found in instrumented module exports. ` +
705→      `Available: ${Object.keys(finalExports.exports).join(", ")}`,
706→    );
707→  }
708→
709→  const reconstructedInputs = inputs.map(reconstructValue);
710→  const metrics = await measureExecution(
711→    () => (fn as (...args: unknown[]) => unknown)(...reconstructedInputs),
712→  );
713→
714→  if (metrics.thrownError) {
715→    sideEffects.push({
716→      kind: "thrown_error",
717→      error_type: metrics.thrownError.error_type,
718→      message: metrics.thrownError.message,
719→      stack: metrics.thrownError.stack,
720→    });
721→  }
722→
723→  // Detect module-level variable changes after execution
724→  for (const key of exportKeys) {
725→    const before = beforeSnapshot.get(key);
726→    const after = finalExports.exports[key];
727→    if (JSON.stringify(before) !== JSON.stringify(after)) {
728→      sideEffects.push({
729→        kind: "global_state_change",
730→        variable: key,
731→        before,
732→        after,
733→      });
734→    }
735→  }
736→
737→  // Build path_constraints: the conjunction of constraints along the taken path
738→  const pathConstraints = branchDecisions.map((bd) => bd.constraint);
739→
740→  return {
741→    return_value: metrics.returnValue ?? null,
742→    thrown_error: metrics.thrownError,
743→    side_effects: sideEffects,
744→    branch_path: branchDecisions,
745→    path_constraints: pathConstraints,
746→    lines_executed: linesExecuted,
747→    performance: metrics.performance,
748→    calls_to_external: externalCalls,
749→    scope_events: scopeEvents,
750→  };
751→}
752→
753→/**
754→ * Build a full ExecuteResponse from a raw execution result.
755→ * Applies side-effect truncation before assembling the response.
756→ */
757→export function buildExecuteResponse(
758→  id: number,
759→  protocolVersion: string,
760→  rawResult: RawExecuteResult,
761→): ExecuteResponse {
762→  const { effects, truncation } = truncateSideEffects(rawResult.side_effects);
763→
764→  const response: ExecuteResponse = {
765→    protocol_version: protocolVersion,
766→    id,
767→    status: "execute",
768→    return_value: rawResult.return_value,
769→    thrown_error: rawResult.thrown_error,
770→    branch_path: rawResult.branch_path,
771→    lines_executed: rawResult.lines_executed,
772→    calls_to_external: rawResult.calls_to_external,
773→    path_constraints: rawResult.path_constraints,
774→    side_effects: effects,
775→    performance: rawResult.performance,
776→    scope_events: rawResult.scope_events,
777→  };
778→
779→  if (truncation) {
780→    response.capture_truncation = truncation;
781→  }
782→
783→  return response;
784→}
