 43→/**
 44→ * The name of the line-recording function inserted into instrumented code.
 45→ * Callers must define this function before executing instrumented code.
 46→ */
 47→export const RECORD_FUNCTION = "__shatter_record";
 48→
 49→/**
 50→ * The name of the branch-recording function inserted into instrumented code.
 51→ * Signature: __shatter_branch(branchId, line, conditionResult, symExpr) → boolean
 52→ */
 53→export const BRANCH_FUNCTION = "__shatter_branch";
 54→
 55→/**
 56→ * The name of the scope-event recording function inserted into instrumented code.
 57→ * Signature: __shatter_scope_event(scopeId, kind) → void
