232→function visitStatementsForDataFlow(
233→  statements: ts.NodeArray<ts.Statement> | ReadonlyArray<ts.Statement>,
234→  resolveName: (name: string) => SymExpr | undefined,
235→  flowMap: Map<string, SymExpr>,
236→): void {
